	private static Set<String> classesInDirectory(Path root) throws IOException {
		Path packageRoot = root.resolve(PACKAGE_PATH);
		Set<String> result = new LinkedHashSet<>();
		try (Stream<Path> paths = Files.list(packageRoot)) {
			paths.filter(path -> path.getFileName().toString().endsWith(".class"))
					.filter(path -> !path.getFileName().toString().contains("$"))
					.map(path -> path.getFileName().toString())
					.map(name -> PACKAGE_NAME + "." + name.substring(0, name.length() - 6))
					.forEach(result::add);
		}
		return result;
	}

	private static Set<String> classesInJar(Path jarPath) throws IOException {
		Set<String> result = new LinkedHashSet<>();
		try (JarFile jar = new JarFile(jarPath.toFile())) {
			jar.stream()
					.map(entry -> entry.getName())
					.filter(name -> name.startsWith(PACKAGE_PATH))
					.filter(name -> name.endsWith(".class"))
					.filter(name -> name.indexOf('/', PACKAGE_PATH.length()) < 0)
					.filter(name -> !name.contains("$"))
					.map(name -> name.substring(0, name.length() - 6).replace('/', '.'))
					.forEach(result::add);
		}
		return result;
	}
